import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"望月弓","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/望月弓.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/望月弓.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/望月弓.md"};function l(p,a,_,i,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"望月弓",tabindex:"-1"},[s("望月弓 "),e("a",{class:"header-anchor",href:"#望月弓","aria-label":'Permalink to "望月弓"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),o('<h1 id="望月弓-1" tabindex="-1">望月弓 <a class="header-anchor" href="#望月弓-1" aria-label="Permalink to &quot;望月弓&quot;">​</a></h1><p>望月弓<br> 魔幻本质<br> 价格：D+500<br> 这是一把乌木制成的长弓,深沉的黑色弓身典雅大方,无任何多余装饰。唯一与众不同的是弓身上隐隐闪动的月色辉光,就像云雾中若隐若现的明月。</p><p>武器类型：长弓<br> 射程：30米<br> 武器伤害：6L<br> 特性：<br> 进行攻击时以自由动作消耗1点能量（须为东方类能量，在购买时决定。），唤醒望月弓中残留的箭意，令这次攻击获得3点破甲或高速。<br> 【雪恨】：每场景一次，人物可以迅捷动作承受至多【决心与耐力附加成功点】不可避免严重伤害为代价，将自身血液化作一枚箭矢，这不会改变搭箭需要的动作，此箭矢在进行一次攻击后即会被消耗。<br> 人物以此箭对单一目标进行攻击时，具有等同于承受的严重伤害的【高速】、【威猛】、【破魔】。</p><p>注：望月弓中寄宿着曾经主人的灵魂，其自愿化作弓的器灵帮助使用者报仇雪恨。因此如果有沟通灵体的手段，可能会与其灵魂产生交流。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
